    one_shot_injected_fan_out_component_extension = (
        MergeResult._extend_conflict_projection_counts_from_fan_out_component_chunks(
            base_projection_counts,
            OneShotIterable(injected_signature_summary_chunks),
            OneShotIterable(injected_code_summary_chunks),
        )
    )

    assert (
        materialized_continuation_projection_counts
        == one_shot_continuation_projection_counts
    )
    assert (
        materialized_injected_continuation_projection_counts
        == materialized_continuation_projection_counts
    )
    assert (
        one_shot_injected_continuation_projection_counts
        == materialized_continuation_projection_counts
    )
    assert materialized_terminal_dispatch_helper_extension == expected_projection_extension
    assert one_shot_terminal_dispatch_helper_extension == expected_projection_extension
    assert materialized_pre_fanned_extension == expected_projection_extension
    assert one_shot_pre_fanned_extension == expected_projection_extension
