def test_merge_result_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_raw_stream_across_splits() -> None:
    (
        _lifecycle_core,
        _relation_canonical,
        replay_sequence,
    ) = build_repeated_lifecycle_pair_mixed_orphan_collision_checkpoint_replicas(
        tx_base=2950
    )
    _, full_results = replay_stream_with_results(replay_sequence)
    full_projection_counts = (
        precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
            full_results
        )
    )
    empty_projection_counts = (
        precompose_projection_continuation_from_summary_chunks_with_empty_chunks(tuple())
    )
    empty_continuation_summary_chunks = conflict_summary_chunks_with_empty_path(tuple())
    component_chunk_configs = (
        ((1,), (1,), False, False),
        ((1, 2), (2, 1), True, False),
        ((2, 1), (1, 2), False, True),
    )

    split_count = 0
    nonempty_continuation_split_count = 0
    nonempty_base_split_count = 0
    for first_split in range(1, len(replay_sequence)):
        for second_split in range(first_split + 1, len(replay_sequence) + 1):
            prefix_merged, prefix_results = replay_stream_with_results(
                replay_sequence[:first_split]
            )
            middle_merged, middle_results = replay_stream_with_results(
                replay_sequence[first_split:second_split],
                start=prefix_merged,
            )
            _suffix_merged, suffix_results = replay_stream_with_results(
                replay_sequence[second_split:],
                start=middle_merged,
            )
            continuation_results = middle_results + suffix_results
            split_count += 1

            base_projection_counts = (
                precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                    prefix_results
                )
            )
            continuation_projection_counts = (
                precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                    continuation_results
                )
            )
            middle_projection_counts = (
                precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                    middle_results
                )
            )
            suffix_projection_counts = (
                precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                    suffix_results
                )
            )
            if continuation_projection_counts[0] or continuation_projection_counts[1]:
                nonempty_continuation_split_count += 1
            if base_projection_counts[0] or base_projection_counts[1]:
                nonempty_base_split_count += 1

            recomposed_continuation_projection_counts = (
                assert_projection_pair_combine_api_equals_summary_pair_projection_one_shot_parity(
                    left_projection_counts=middle_projection_counts,
                    right_projection_counts=suffix_projection_counts,
                )
            )
            assert (
                recomposed_continuation_projection_counts
                == continuation_projection_counts
            )
            recomposed_continuation_summary_chunks = (
                (tuple(), tuple()),
                recomposed_continuation_projection_counts,
                (tuple(), tuple()),
            )
            continuation_summary_chunks = conflict_summary_chunks_with_empty_path(
                continuation_results
            )
            for (
                signature_chunk_size_cycle,
                code_chunk_size_cycle,
                permute_signature_chunks,
                permute_code_chunks,
            ) in component_chunk_configs:
                direct_extended_projection_counts = (
                    assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                        base_projection_counts=base_projection_counts,
                        continuation_summary_chunks=continuation_summary_chunks,
                        signature_chunk_size_cycle=signature_chunk_size_cycle,
                        code_chunk_size_cycle=code_chunk_size_cycle,
                        permute_signature_chunks=permute_signature_chunks,
                        permute_code_chunks=permute_code_chunks,
                    )
                )
                recomposed_extended_projection_counts = (
                    assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                        base_projection_counts=base_projection_counts,
                        continuation_summary_chunks=recomposed_continuation_summary_chunks,
                        signature_chunk_size_cycle=signature_chunk_size_cycle,
                        code_chunk_size_cycle=code_chunk_size_cycle,
                        permute_signature_chunks=permute_signature_chunks,
                        permute_code_chunks=permute_code_chunks,
                    )
                )
                empty_base_extended_projection_counts = (
                    assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                        base_projection_counts=empty_projection_counts,
                        continuation_summary_chunks=continuation_summary_chunks,
                        signature_chunk_size_cycle=signature_chunk_size_cycle,
                        code_chunk_size_cycle=code_chunk_size_cycle,
                        permute_signature_chunks=permute_signature_chunks,
                        permute_code_chunks=permute_code_chunks,
                    )
                )
                empty_continuation_extended_projection_counts = (
                    assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                        base_projection_counts=base_projection_counts,
                        continuation_summary_chunks=empty_continuation_summary_chunks,
                        signature_chunk_size_cycle=signature_chunk_size_cycle,
                        code_chunk_size_cycle=code_chunk_size_cycle,
                        permute_signature_chunks=permute_signature_chunks,
                        permute_code_chunks=permute_code_chunks,
                    )
                )

                assert (
                    direct_extended_projection_counts
                    == recomposed_extended_projection_counts
                )
                assert direct_extended_projection_counts == full_projection_counts
                assert (
                    empty_base_extended_projection_counts
                    == continuation_projection_counts
                )
                assert (
                    empty_continuation_extended_projection_counts
                    == base_projection_counts
                )

    assert split_count > 0
    assert nonempty_continuation_split_count > 0
    assert nonempty_base_split_count > 0


def test_merge_result_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_raw_stream_checkpoint_permutations() -> None:
    _, replay_sequence = build_mixed_orphan_collision_checkpoint_replicas(tx_base=2960)
    empty_projection_counts = (
        precompose_projection_continuation_from_summary_chunks_with_empty_chunks(tuple())
    )
    empty_continuation_summary_chunks = conflict_summary_chunks_with_empty_path(tuple())

    nonempty_continuation_permutation_count = 0
    nonempty_base_permutation_count = 0
    for order in itertools.permutations(range(len(replay_sequence))):
        ordered_replicas = [replay_sequence[index] for index in order]
        first_split = len(ordered_replicas) // 3
        if first_split == 0:
            first_split = 1
        second_split = (2 * len(ordered_replicas)) // 3
        if second_split <= first_split:
            second_split = first_split + 1
        if second_split > len(ordered_replicas):
            second_split = len(ordered_replicas)

        prefix_merged, prefix_results = replay_stream_with_results(
            ordered_replicas[:first_split]
        )
        unsplit_middle_merged, unsplit_middle_results = replay_stream_with_results(
            ordered_replicas[first_split:second_split],
            start=prefix_merged,
        )
        unsplit_suffix_merged, unsplit_suffix_results = replay_stream_with_results(
            ordered_replicas[second_split:],
            start=unsplit_middle_merged,
        )
        resumed_middle_merged, resumed_middle_results = replay_stream_with_results(
            ordered_replicas[first_split:second_split],
            start=prefix_merged.checkpoint(),
        )
        resumed_suffix_merged, resumed_suffix_results = replay_stream_with_results(
            ordered_replicas[second_split:],
            start=resumed_middle_merged.checkpoint(),
        )
        full_merged, full_results = replay_stream_with_results(ordered_replicas)

        base_projection_counts = (
            precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                prefix_results
            )
        )
        full_projection_counts = (
            precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                full_results
            )
        )
        unsplit_continuation_projection_counts = (
            precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                unsplit_middle_results + unsplit_suffix_results
            )
        )
        resumed_continuation_projection_counts = (
            precompose_projection_continuation_from_summary_chunks_with_empty_chunks(
                resumed_middle_results + resumed_suffix_results
            )
        )
        if (
            unsplit_continuation_projection_counts[0]
            or unsplit_continuation_projection_counts[1]
        ):
            nonempty_continuation_permutation_count += 1
        if base_projection_counts[0] or base_projection_counts[1]:
            nonempty_base_permutation_count += 1

        unsplit_extended_projection_counts = (
            assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                base_projection_counts=base_projection_counts,
                continuation_summary_chunks=conflict_summary_chunks_with_empty_path(
                    unsplit_middle_results + unsplit_suffix_results
                ),
                signature_chunk_size_cycle=(1, 2),
                code_chunk_size_cycle=(2, 1),
                permute_signature_chunks=True,
                permute_code_chunks=True,
            )
        )
        resumed_extended_projection_counts = (
            assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                base_projection_counts=base_projection_counts,
                continuation_summary_chunks=conflict_summary_chunks_with_empty_path(
                    resumed_middle_results + resumed_suffix_results
                ),
                signature_chunk_size_cycle=(1, 2),
                code_chunk_size_cycle=(2, 1),
                permute_signature_chunks=True,
                permute_code_chunks=True,
            )
        )
        unsplit_empty_base_extended_projection_counts = (
            assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                base_projection_counts=empty_projection_counts,
                continuation_summary_chunks=conflict_summary_chunks_with_empty_path(
                    unsplit_middle_results + unsplit_suffix_results
                ),
                signature_chunk_size_cycle=(1, 2),
                code_chunk_size_cycle=(2, 1),
                permute_signature_chunks=True,
                permute_code_chunks=True,
            )
        )
        resumed_empty_base_extended_projection_counts = (
            assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                base_projection_counts=empty_projection_counts,
                continuation_summary_chunks=conflict_summary_chunks_with_empty_path(
                    resumed_middle_results + resumed_suffix_results
                ),
                signature_chunk_size_cycle=(1, 2),
                code_chunk_size_cycle=(2, 1),
                permute_signature_chunks=True,
                permute_code_chunks=True,
            )
        )
        empty_continuation_extended_projection_counts = (
            assert_projection_summary_chunk_extension_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_equals_fan_out_component_chunks_one_shot_stream_parity(
                base_projection_counts=base_projection_counts,
                continuation_summary_chunks=empty_continuation_summary_chunks,
                signature_chunk_size_cycle=(1, 2),
                code_chunk_size_cycle=(2, 1),
                permute_signature_chunks=True,
                permute_code_chunks=True,
            )
        )

        assert unsplit_extended_projection_counts == resumed_extended_projection_counts
        assert unsplit_extended_projection_counts == full_projection_counts
        assert (
            unsplit_empty_base_extended_projection_counts
            == resumed_empty_base_extended_projection_counts
        )
        assert (
            unsplit_empty_base_extended_projection_counts
            == unsplit_continuation_projection_counts
        )
        assert (
            unsplit_continuation_projection_counts
            == resumed_continuation_projection_counts
        )
        assert empty_continuation_extended_projection_counts == base_projection_counts
        assert (
            unsplit_suffix_merged.relation_state_signatures()
            == full_merged.relation_state_signatures()
        )
        assert (
            unsplit_suffix_merged.revision_state_signatures()
            == full_merged.revision_state_signatures()
        )
        assert (
            resumed_suffix_merged.relation_state_signatures()
            == full_merged.relation_state_signatures()
        )
        assert (
            resumed_suffix_merged.revision_state_signatures()
            == full_merged.revision_state_signatures()
        )

    assert nonempty_continuation_permutation_count > 0
    assert nonempty_base_permutation_count > 0


def assert_projection_summary_chunk_extension_fan_out_components_terminal_components_dispatch_terminal_helper_equals_pre_fanned_component_chunks_independent_component_chunk_stream_dispatch_one_shot_stream_parity(
    *,
    base_projection_counts: tuple[tuple, tuple],
    continuation_summary_chunks: tuple[tuple[tuple, tuple], ...],
    signature_chunk_size_cycle: tuple[int, ...],
    code_chunk_size_cycle: tuple[int, ...],
    permute_signature_chunks: bool,
    permute_code_chunks: bool,
) -> tuple[tuple, tuple]:
    empty_summary_chunk = (tuple(), tuple())
    expected_continuation_projection_counts = (
        MergeResult.combine_conflict_summaries_from_chunks(continuation_summary_chunks)
    )
    expected_projection_extension = (
        MergeResult.extend_conflict_projection_counts_with_precomposed_continuation(
            base_projection_counts,
            expected_continuation_projection_counts,
        )
    )
    (
        continuation_signature_summary_chunks,
        continuation_code_summary_chunks,
    ) = build_independently_chunked_conflict_projection_component_summary_streams(
        continuation_summary_chunks,
        signature_chunk_size_cycle=signature_chunk_size_cycle,
        code_chunk_size_cycle=code_chunk_size_cycle,
        permute_signature_chunks=permute_signature_chunks,
        permute_code_chunks=permute_code_chunks,
    )
    injected_signature_summary_chunks = (
        (empty_summary_chunk,)
        + continuation_signature_summary_chunks
        + (empty_summary_chunk,)
    )
    injected_code_summary_chunks = (
        (empty_summary_chunk,) + continuation_code_summary_chunks + (empty_summary_chunk,)
    )

    assert (
        MergeResult.stream_conflict_signature_counts_from_summary_chunks(
            continuation_signature_summary_chunks
        )
        == expected_continuation_projection_counts[0]
    )
    assert (
        MergeResult.stream_conflict_signature_counts_from_summary_chunks(
            OneShotIterable(continuation_signature_summary_chunks)
        )
        == expected_continuation_projection_counts[0]
    )
    assert (
        MergeResult.stream_conflict_signature_counts_from_summary_chunks(
            injected_signature_summary_chunks
        )
        == expected_continuation_projection_counts[0]
    )
    assert (
        MergeResult.stream_conflict_code_counts_from_summary_chunks(
            continuation_code_summary_chunks
        )
        == expected_continuation_projection_counts[1]
    )
    assert (
        MergeResult.stream_conflict_code_counts_from_summary_chunks(
            OneShotIterable(continuation_code_summary_chunks)
        )
        == expected_continuation_projection_counts[1]
    )
    assert (
        MergeResult.stream_conflict_code_counts_from_summary_chunks(
            injected_code_summary_chunks
        )
        == expected_continuation_projection_counts[1]
    )

    projection_candidates = (
        (continuation_signature_summary_chunks, continuation_code_summary_chunks),
        (injected_signature_summary_chunks, injected_code_summary_chunks),
    )
    for signature_summary_chunks, code_summary_chunks in projection_candidates:
        materialized_terminal_helper_extension = (
            MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_components_terminal_components_dispatch_terminal_helper(
                base_projection_counts,
                signature_summary_chunks,
                code_summary_chunks,
            )
        )
        one_shot_terminal_helper_extension = (
            MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_components_terminal_components_dispatch_terminal_helper(
                base_projection_counts,
                OneShotIterable(signature_summary_chunks),
                OneShotIterable(code_summary_chunks),
            )
        )
        materialized_terminal_helper_independent_dispatch_extension = (
            MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_components_terminal_components_dispatch_terminal_helper_independent_component_dispatch(
                base_projection_counts,
                signature_summary_chunks,
                code_summary_chunks,
            )
        )
        one_shot_terminal_helper_independent_dispatch_extension = (
            MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_components_terminal_components_dispatch_terminal_helper_independent_component_dispatch(
                base_projection_counts,
                OneShotIterable(signature_summary_chunks),
                OneShotIterable(code_summary_chunks),
            )
        )
        materialized_pre_fanned_independent_dispatch_extension = (
            MergeResult._extend_conflict_projection_counts_from_pre_fanned_component_chunks_independent_component_dispatch(
                base_projection_counts,
                signature_summary_chunks,
                code_summary_chunks,
            )
        )
        one_shot_pre_fanned_independent_dispatch_extension = (
            MergeResult._extend_conflict_projection_counts_from_pre_fanned_component_chunks_independent_component_dispatch(
                base_projection_counts,
                OneShotIterable(signature_summary_chunks),
                OneShotIterable(code_summary_chunks),
            )
        )
        materialized_fan_out_component_extension = (
            MergeResult._extend_conflict_projection_counts_from_fan_out_component_chunks(
                base_projection_counts,
                signature_summary_chunks,
                code_summary_chunks,
            )
        )
        one_shot_fan_out_component_extension = (
            MergeResult._extend_conflict_projection_counts_from_fan_out_component_chunks(
                base_projection_counts,
                OneShotIterable(signature_summary_chunks),
                OneShotIterable(code_summary_chunks),
            )
        )

        assert materialized_terminal_helper_extension == expected_projection_extension
        assert one_shot_terminal_helper_extension == expected_projection_extension
        assert (
            materialized_terminal_helper_independent_dispatch_extension
            == expected_projection_extension
        )
        assert (
            one_shot_terminal_helper_independent_dispatch_extension
            == expected_projection_extension
        )
        assert (
            materialized_pre_fanned_independent_dispatch_extension
            == expected_projection_extension
        )
        assert one_shot_pre_fanned_independent_dispatch_extension == expected_projection_extension
        assert materialized_fan_out_component_extension == expected_projection_extension
        assert one_shot_fan_out_component_extension == expected_projection_extension
        assert (
            materialized_terminal_helper_extension
            == materialized_terminal_helper_independent_dispatch_extension
        )
        assert (
            one_shot_terminal_helper_extension
            == one_shot_terminal_helper_independent_dispatch_extension
        )
        assert (
            materialized_terminal_helper_extension
            == materialized_pre_fanned_independent_dispatch_extension
        )
        assert (
            one_shot_terminal_helper_extension
            == one_shot_pre_fanned_independent_dispatch_extension
        )
        assert (
            materialized_terminal_helper_extension
            == materialized_fan_out_component_extension
        )
        assert one_shot_terminal_helper_extension == one_shot_fan_out_component_extension

    return expected_projection_extension


