def test_merge_result_projection_summary_chunk_extension_fan_out_public_api_equals_internal_fan_out_public_entrypoint_shim_raw_stream_checkpoint_permutations() -> None:
    _, replay_sequence = build_mixed_orphan_collision_checkpoint_replicas(tx_base=3200)
