def assert_projection_summary_chunk_extension_fan_out_public_components_equals_internal_components_components_dispatch_one_shot_stream_parity(
    *,
    base_projection_counts: tuple[tuple, tuple],
    continuation_summary_chunks: tuple[tuple[tuple, tuple], ...],
) -> tuple[tuple, tuple]:
    materialized_public_components = (
        MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_public_components(
            base_projection_counts,
            continuation_summary_chunks,
        )
    )
    one_shot_public_components = (
        MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_public_components(
            base_projection_counts,
            OneShotIterable(continuation_summary_chunks),
        )
    )
    materialized_public_components_components = (
        MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_public_components_components(
            base_projection_counts,
            continuation_summary_chunks,
        )
    )
    one_shot_public_components_components = (
        MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_public_components_components(
            base_projection_counts,
            OneShotIterable(continuation_summary_chunks),
        )
    )
    materialized_public_components_dispatch = (
        MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_public_components_dispatch(
            base_projection_counts,
            continuation_summary_chunks,
        )
    )
    one_shot_public_components_dispatch = (
        MergeResult._extend_conflict_projection_counts_from_summary_chunks_via_fan_out_public_components_dispatch(
            base_projection_counts,
            OneShotIterable(continuation_summary_chunks),
        )
    )
    assert (
        materialized_public_components
        == assert_projection_summary_chunk_extension_fan_out_public_components_equals_route_components_one_shot_stream_parity(
            base_projection_counts=base_projection_counts,
            continuation_summary_chunks=continuation_summary_chunks,
        )
    )
    assert materialized_public_components == one_shot_public_components
    assert materialized_public_components == materialized_public_components_components
    assert materialized_public_components == one_shot_public_components_components
    assert materialized_public_components == materialized_public_components_dispatch
    assert materialized_public_components == one_shot_public_components_dispatch
    return materialized_public_components


