def test_attach_relation_requires_existing_revisions_and_is_symmetric_for_contradicts() -> None:
    store = KnowledgeStore()
    core = ClaimCore(
        claim_type="residence",
        slots={"subject": "Ada Lovelace"},
    )

    rev_a = store.assert_revision(
        core=core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=1, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=6000,
    )
    rev_b = store.assert_revision(
        core=core,
        assertion="Ada lives in Paris",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=2, recorded_at=dt(2024, 1, 3)),
        provenance=Provenance(source="source_b"),
        confidence_bp=6000,
    )

    edge_ab = store.attach_relation(
        relation_type="contradicts",
        from_revision_id=rev_a.revision_id,
        to_revision_id=rev_b.revision_id,
        transaction_time=TransactionTime(tx_id=3, recorded_at=dt(2024, 1, 4)),
    )
    edge_ba = store.attach_relation(
        relation_type="contradicts",
        from_revision_id=rev_b.revision_id,
        to_revision_id=rev_a.revision_id,
        transaction_time=TransactionTime(tx_id=3, recorded_at=dt(2024, 1, 4)),
    )

    assert edge_ab.relation_id == edge_ba.relation_id
    assert len(store.relations) == 1

    with pytest.raises(KeyError):
        store.attach_relation(
            relation_type="supports",
            from_revision_id="missing",
            to_revision_id=rev_a.revision_id,
            transaction_time=TransactionTime(tx_id=4, recorded_at=dt(2024, 1, 5)),
        )


def test_query_relations_as_of_respects_tx_cutoff_and_revision_filter() -> None:
    store = KnowledgeStore()
    core = ClaimCore(
        claim_type="residence",
        slots={"subject": "Ada Lovelace"},
    )

    rev_a = store.assert_revision(
        core=core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=1, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=6000,
    )
    rev_b = store.assert_revision(
        core=core,
        assertion="Ada lives in Paris",
        valid_time=ValidTime(start=dt(2024, 2, 1), end=None),
        transaction_time=TransactionTime(tx_id=2, recorded_at=dt(2024, 2, 2)),
        provenance=Provenance(source="source_b"),
        confidence_bp=6000,
    )

    rel_1 = store.attach_relation(
        relation_type="supports",
        from_revision_id=rev_a.revision_id,
        to_revision_id=rev_b.revision_id,
        transaction_time=TransactionTime(tx_id=3, recorded_at=dt(2024, 2, 3)),
    )
    rel_2 = store.attach_relation(
        relation_type="depends_on",
        from_revision_id=rev_b.revision_id,
        to_revision_id=rev_a.revision_id,
        transaction_time=TransactionTime(tx_id=4, recorded_at=dt(2024, 2, 4)),
    )

    assert store.query_relations_as_of(tx_id=2) == ()
    assert store.query_relations_as_of(tx_id=3) == (rel_1,)

    visible_ids = tuple(
        relation.relation_id
        for relation in store.query_relations_as_of(tx_id=4, revision_id=rev_a.revision_id)
    )
    assert visible_ids == tuple(sorted([rel_1.relation_id, rel_2.relation_id]))


