def test_query_relations_as_of_active_only_filters_retracted_endpoints() -> None:
    store = KnowledgeStore()
    residence_core = ClaimCore(
        claim_type="residence",
        slots={"subject": "Ada Lovelace"},
    )
    evidence_core = ClaimCore(
        claim_type="document",
        slots={"id": "archive-1"},
    )

    residence_asserted = store.assert_revision(
        core=residence_core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=1, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
    )
    evidence_revision = store.assert_revision(
        core=evidence_core,
        assertion="Archive A records London residence",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=1, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_doc"),
        confidence_bp=9000,
    )
    relation = store.attach_relation(
        relation_type="derived_from",
        from_revision_id=residence_asserted.revision_id,
        to_revision_id=evidence_revision.revision_id,
        transaction_time=TransactionTime(tx_id=2, recorded_at=dt(2024, 1, 3)),
    )
    store.assert_revision(
        core=residence_core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=3, recorded_at=dt(2024, 1, 4)),
        provenance=Provenance(source="source_b"),
        confidence_bp=7000,
        status="retracted",
    )

    assert store.query_relations_as_of(tx_id=3) == (relation,)
    assert (
        store.query_relations_as_of(
            tx_id=2,
            valid_at=dt(2024, 6, 1),
            active_only=True,
        )
        == (relation,)
    )
    assert (
        store.query_relations_as_of(
            tx_id=3,
            valid_at=dt(2024, 6, 1),
            active_only=True,
        )
        == ()
    )


def test_merge_classifies_orphan_relation_endpoints_and_skips_edges() -> None:
    left = KnowledgeStore()
    left.assert_revision(
        core=ClaimCore(claim_type="residence", slots={"subject": "Ada Lovelace"}),
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=1, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
    )

    right = KnowledgeStore()
    orphan_relation = RelationEdge(
        relation_type="supports",
        from_revision_id="missing-from-revision",
        to_revision_id="missing-to-revision",
        transaction_time=TransactionTime(tx_id=2, recorded_at=dt(2024, 1, 3)),
    )
    right.relations[orphan_relation.relation_id] = orphan_relation

    result = left.merge(right)

    orphan_conflicts = [
        conflict
        for conflict in result.conflicts
        if conflict.code == ConflictCode.ORPHAN_RELATION_ENDPOINT
    ]
    assert len(orphan_conflicts) == 1
    assert orphan_conflicts[0].entity_id == orphan_relation.relation_id
    assert (
        orphan_conflicts[0].details
        == "relation references missing revision endpoints: missing-from-revision, missing-to-revision"
    )
    assert result.conflict_code_counts() == (
        (ConflictCode.ORPHAN_RELATION_ENDPOINT.value, 1),
    )
    assert result.conflict_summary() == (
        result.conflict_signature_counts(),
        result.conflict_code_counts(),
    )
    assert result.merged.query_relations_as_of(tx_id=10) == ()


