def test_merge_permutation_replay_produces_stable_lifecycle_conflicts() -> None:
    core = ClaimCore(
        claim_type="residence",
        slots={"subject": "Ada Lovelace"},
    )

    replica_a = KnowledgeStore()
    rev_a = replica_a.assert_revision(
        core=core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=12, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
        status="asserted",
    )

    replica_b = KnowledgeStore()
    rev_b = replica_b.assert_revision(
        core=core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=12, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_b"),
        confidence_bp=7000,
        status="retracted",
    )

    replica_c = KnowledgeStore()
    rev_c = replica_c.assert_revision(
        core=core,
        assertion="Ada lives in Paris",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=12, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_c"),
        confidence_bp=7000,
        status="asserted",
    )

    replicas = [replica_a, replica_b, replica_c]
    expected_revision_ids = {rev_a.revision_id, rev_b.revision_id, rev_c.revision_id}
    baseline_signatures = None

    for order in itertools.permutations(range(len(replicas))):
        merged = KnowledgeStore()
        observed_conflicts = []
        for index in order:
            merge_result = merged.merge(replicas[index])
            merged = merge_result.merged
            observed_conflicts.extend(merge_result.conflicts)

        signatures = tuple(
            sorted((conflict.code.value, conflict.entity_id, conflict.details) for conflict in observed_conflicts)
        )
        if baseline_signatures is None:
            baseline_signatures = signatures
        else:
            assert signatures == baseline_signatures

        lifecycle_count = sum(
            1
            for conflict in observed_conflicts
            if conflict.code == ConflictCode.COMPETING_LIFECYCLE_SAME_SLOT
        )
        revision_count = sum(
            1
            for conflict in observed_conflicts
            if conflict.code == ConflictCode.COMPETING_REVISION_SAME_SLOT
        )
        assert lifecycle_count == 2
        assert revision_count == 1
        assert (
            merged.query_as_of(core.core_id, valid_at=dt(2024, 6, 1), tx_id=12)
            is None
        )
        assert {
            revision.revision_id for revision in merged.iter_core_revisions(core.core_id)
        } == expected_revision_ids


def test_merge_replay_with_retraction_and_relations_is_deterministic() -> None:
    core = ClaimCore(
        claim_type="residence",
        slots={"subject": "Ada Lovelace"},
    )

    left = KnowledgeStore()
    left.assert_revision(
        core=core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=1, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
    )

    right = KnowledgeStore()
    rev_asserted = right.assert_revision(
        core=core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=1, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
    )
    rev_retracted = right.assert_revision(
        core=core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=2, recorded_at=dt(2024, 1, 3)),
        provenance=Provenance(source="source_b"),
        confidence_bp=7000,
        status="retracted",
    )
    relation = right.attach_relation(
        relation_type="derived_from",
        from_revision_id=rev_retracted.revision_id,
        to_revision_id=rev_asserted.revision_id,
        transaction_time=TransactionTime(tx_id=3, recorded_at=dt(2024, 1, 4)),
    )

    merged_lr = left.merge(right)
    merged_rl = right.merge(left)

    assert merged_lr.conflicts == ()
    assert merged_rl.conflicts == ()
    assert (
        merged_lr.merged.query_as_of(core.core_id, valid_at=dt(2024, 6, 1), tx_id=2)
        is None
    )
    assert (
        merged_rl.merged.query_as_of(core.core_id, valid_at=dt(2024, 6, 1), tx_id=2)
        is None
    )

    left_revision_ids = {
        revision.revision_id
        for revision in merged_lr.merged.iter_core_revisions(core.core_id)
    }
    right_revision_ids = {
        revision.revision_id
        for revision in merged_rl.merged.iter_core_revisions(core.core_id)
    }
    assert left_revision_ids == right_revision_ids

    assert merged_lr.merged.query_relations_as_of(tx_id=2) == ()
    assert merged_lr.merged.query_relations_as_of(tx_id=3) == (relation,)
    assert merged_rl.merged.query_relations_as_of(tx_id=3) == (relation,)


