def test_merge_replayed_orphan_relation_is_idempotent() -> None:
    residence_core = ClaimCore(
        claim_type="residence",
        slots={"subject": "Ada Lovelace"},
    )
    evidence_core = ClaimCore(
        claim_type="document",
        slots={"id": "archive-1"},
    )

    endpoints_replica = KnowledgeStore()
    residence_revision = endpoints_replica.assert_revision(
        core=residence_core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=60, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
    )
    evidence_revision = endpoints_replica.assert_revision(
        core=evidence_core,
        assertion="Archive A records London residence",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=61, recorded_at=dt(2024, 1, 3)),
        provenance=Provenance(source="source_doc"),
        confidence_bp=9000,
    )

    orphan_replica = KnowledgeStore()
    relation = RelationEdge(
        relation_type="derived_from",
        from_revision_id=residence_revision.revision_id,
        to_revision_id=evidence_revision.revision_id,
        transaction_time=TransactionTime(tx_id=70, recorded_at=dt(2024, 1, 5)),
    )
    orphan_replica.relations[relation.relation_id] = relation

    first_merge = KnowledgeStore().merge(orphan_replica)
    second_merge = first_merge.merged.merge(orphan_replica)
    promoted_merge = second_merge.merged.merge(endpoints_replica)
    replay_after_promotion = promoted_merge.merged.merge(orphan_replica)

    first_orphan_conflicts = [
        conflict
        for conflict in first_merge.conflicts
        if conflict.code == ConflictCode.ORPHAN_RELATION_ENDPOINT
    ]
    second_orphan_conflicts = [
        conflict
        for conflict in second_merge.conflicts
        if conflict.code == ConflictCode.ORPHAN_RELATION_ENDPOINT
    ]

    assert len(first_orphan_conflicts) == 1
    assert len(second_orphan_conflicts) == 0
    assert promoted_merge.conflicts == ()
    assert replay_after_promotion.conflicts == ()
    assert replay_after_promotion.merged.query_relations_as_of(tx_id=69) == ()
    assert replay_after_promotion.merged.query_relations_as_of(tx_id=70) == (relation,)
    assert len(replay_after_promotion.merged.query_relations_as_of(tx_id=999)) == 1


