def test_merge_relation_id_collision_replaces_pending_with_canonical_payload() -> None:
    residence_core = ClaimCore(
        claim_type="residence",
        slots={"subject": "Ada Lovelace"},
    )
    evidence_core = ClaimCore(
        claim_type="document",
        slots={"id": "archive-1"},
    )

    endpoints_replica = KnowledgeStore()
    residence_revision = endpoints_replica.assert_revision(
        core=residence_core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=100, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
    )
    evidence_revision = endpoints_replica.assert_revision(
        core=evidence_core,
        assertion="Archive A records London residence",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=101, recorded_at=dt(2024, 1, 3)),
        provenance=Provenance(source="source_doc"),
        confidence_bp=9000,
    )

    pending_replica = KnowledgeStore()
    relation_pending = RelationEdge(
        relation_type="supports",
        from_revision_id=residence_revision.revision_id,
        to_revision_id=evidence_revision.revision_id,
        transaction_time=TransactionTime(tx_id=110, recorded_at=dt(2024, 1, 5)),
    )
    pending_replica.relations[relation_pending.relation_id] = relation_pending

    collision_replica = KnowledgeStore()
    collision_replica.assert_revision(
        core=residence_core,
        assertion="Ada lives in London",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=100, recorded_at=dt(2024, 1, 2)),
        provenance=Provenance(source="source_a"),
        confidence_bp=7000,
    )
    collision_replica.assert_revision(
        core=evidence_core,
        assertion="Archive A records London residence",
        valid_time=ValidTime(start=dt(2024, 1, 1), end=None),
        transaction_time=TransactionTime(tx_id=101, recorded_at=dt(2024, 1, 3)),
        provenance=Provenance(source="source_doc"),
        confidence_bp=9000,
    )
    relation_canonical = RelationEdge(
        relation_type="depends_on",
        from_revision_id=residence_revision.revision_id,
        to_revision_id=evidence_revision.revision_id,
        transaction_time=TransactionTime(tx_id=110, recorded_at=dt(2024, 1, 5)),
    )
    relation_canonical = force_relation_id(
        relation_canonical,
        relation_pending.relation_id,
    )
    collision_replica.relations[relation_canonical.relation_id] = relation_canonical

    first_merge = KnowledgeStore().merge(pending_replica)
    second_merge = first_merge.merged.merge(collision_replica)
    third_merge = second_merge.merged.merge(endpoints_replica)

    assert any(
        conflict.code == ConflictCode.RELATION_ID_COLLISION
        for conflict in second_merge.conflicts
    )
    assert third_merge.merged.query_relations_as_of(tx_id=109) == ()
    assert third_merge.merged.query_relations_as_of(tx_id=110) == (relation_canonical,)
    assert len(third_merge.merged.query_relations_as_of(tx_id=999)) == 1


