def test_merge_checkpoint_boundary_replay_matches_unsplit_conflicts_and_state() -> None:
    relation_canonical, (
        replica_supports,
        replica_derived,
        replica_contradicts,
    ) = build_three_payload_relation_collision_replicas(tx_base=600)

    replay_sequence = [
        replica_supports,
        replica_derived,
        replica_contradicts,
        replica_derived,
        replica_supports,
    ]
    unsplit_merged, unsplit_conflicts = replay_stream(replay_sequence)
    unsplit_signatures = KnowledgeStore.conflict_signatures(unsplit_conflicts)

    assert unsplit_merged.query_relations_as_of(
        tx_id=relation_canonical.transaction_time.tx_id
    ) == (relation_canonical,)
    assert unsplit_merged.query_relations_as_of(tx_id=9999) == (relation_canonical,)

    for split_index in range(1, len(replay_sequence)):
        prefix_merged, prefix_conflicts = replay_stream(replay_sequence[:split_index])
        resumed_merged, resumed_suffix_conflicts = replay_stream(
            replay_sequence[split_index:],
            start=prefix_merged.checkpoint(),
        )
        resumed_signatures = KnowledgeStore.conflict_signatures(
            prefix_conflicts + resumed_suffix_conflicts
        )

        assert resumed_signatures == unsplit_signatures
        assert resumed_merged.query_relations_as_of(
            tx_id=relation_canonical.transaction_time.tx_id
        ) == (relation_canonical,)
        assert resumed_merged.query_relations_as_of(tx_id=9999) == (relation_canonical,)

        replay_unsplit = unsplit_merged.merge(replica_supports)
        replay_resumed = resumed_merged.merge(replica_supports)
        assert replay_resumed.conflict_signatures() == replay_unsplit.conflict_signatures()
        assert replay_resumed.merged.query_relations_as_of(tx_id=9999) == (
            relation_canonical,
        )


