def test_merge_checkpoint_boundary_continuation_result_summaries_match_unsplit() -> None:
    tx_base = 1400
    (
        lifecycle_core,
        relation_canonical,
        replay_sequence,
    ) = build_repeated_lifecycle_pair_mixed_orphan_collision_checkpoint_replicas(
        tx_base=tx_base
    )

    unsplit_full_merged, _ = replay_stream(replay_sequence)

    for split_index in range(1, len(replay_sequence)):
        prefix_merged, _ = replay_stream(replay_sequence[:split_index])
        unsplit_continued_merged, unsplit_continuation_results = replay_stream_with_results(
            replay_sequence[split_index:],
            start=prefix_merged,
        )
        resumed_merged, resumed_results = replay_stream_with_results(
            replay_sequence[split_index:],
            start=prefix_merged.checkpoint(),
        )

        assert len(resumed_results) == len(unsplit_continuation_results)
        for unsplit_result, resumed_result in zip(
            unsplit_continuation_results,
            resumed_results,
        ):
            assert (
                resumed_result.conflict_signature_counts()
                == unsplit_result.conflict_signature_counts()
            )
            assert (
                resumed_result.conflict_code_counts()
                == unsplit_result.conflict_code_counts()
            )
            assert resumed_result.conflict_summary() == unsplit_result.conflict_summary()

        assert MergeResult.stream_conflict_signature_counts(
            resumed_results
        ) == MergeResult.stream_conflict_signature_counts(unsplit_continuation_results)
        assert MergeResult.stream_conflict_code_counts(
            resumed_results
        ) == MergeResult.stream_conflict_code_counts(unsplit_continuation_results)
        assert MergeResult.stream_conflict_summary(
            resumed_results
        ) == MergeResult.stream_conflict_summary(unsplit_continuation_results)

        assert (
            resumed_merged.relation_state_signatures()
            == unsplit_continued_merged.relation_state_signatures()
        )
        assert (
            resumed_merged.revision_state_signatures()
            == unsplit_continued_merged.revision_state_signatures()
        )
        assert (
            resumed_merged.relation_state_signatures()
            == unsplit_full_merged.relation_state_signatures()
        )
        assert (
            resumed_merged.revision_state_signatures()
            == unsplit_full_merged.revision_state_signatures()
        )
        assert resumed_merged.pending_relation_ids() == ()
        assert resumed_merged.query_relations_as_of(
            tx_id=relation_canonical.transaction_time.tx_id
        ) == (relation_canonical,)
        assert resumed_merged.query_relations_as_of(tx_id=9999) == (relation_canonical,)
        assert (
            resumed_merged.query_as_of(
                lifecycle_core.core_id,
                valid_at=dt(2024, 6, 1),
                tx_id=tx_base + 20,
            )
            is None
        )


